import java.util.concurrent.Executors

class MaintenanceTaskService : Service() {

    companion object {
        const val ACTION_PROCESS_TASK = "com.example.systemoptimization.action.PROCESS_TASK"

        const val EXTRA_TASK_TYPE = "extra_task_type"
        const val EXTRA_SYNC_TARGET = "extra_sync_target"
        const val EXTRA_CLEANUP_SCOPE = "extra_cleanup_scope"
        const val EXTRA_FORCE = "extra_force"

        const val TASK_SYNC = "task_sync"
        const val TASK_CLEANUP = "task_cleanup"

        private const val TAG = "MaintenanceTaskService"
    }

    private lateinit var executor: ExecutorService

    override fun onCreate() {
        super.onCreate()
        executor = Executors.newSingleThreadExecutor()
    }

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        if (intent == null) {
            stopSelf(startId)
            return START_NOT_STICKY
        }

        if (intent.action != ACTION_PROCESS_TASK) {
            Log.w(TAG, "Unsupported action: ${intent.action}")
            stopSelf(startId)
            return START_NOT_STICKY
        }

        val taskType = intent.getStringExtra(EXTRA_TASK_TYPE)
        if (taskType.isNullOrBlank()) {
